def _document_db_collection_to_nested(
    document_db_collection: DocumentDBCollection,
) -> DocumentDBCollectionNested:
    """Convert flat DocumentDBCollection to nested format."""
    attrs = DocumentDBCollectionAttributes()
    _populate_document_db_collection_attrs(attrs, document_db_collection)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        document_db_collection,
        _DOCUMENT_DB_COLLECTION_REL_FIELDS,
        DocumentDBCollectionRelationshipAttributes,
    )
    return DocumentDBCollectionNested(
        guid=document_db_collection.guid,
        type_name=document_db_collection.type_name,
        status=document_db_collection.status,
        version=document_db_collection.version,
        create_time=document_db_collection.create_time,
        update_time=document_db_collection.update_time,
        created_by=document_db_collection.created_by,
        updated_by=document_db_collection.updated_by,
        classifications=document_db_collection.classifications,
        classification_names=document_db_collection.classification_names,
        meanings=document_db_collection.meanings,
        labels=document_db_collection.labels,
        business_attributes=document_db_collection.business_attributes,
        custom_attributes=document_db_collection.custom_attributes,
        pending_tasks=document_db_collection.pending_tasks,
        proxy=document_db_collection.proxy,
        is_incomplete=document_db_collection.is_incomplete,
        provenance_type=document_db_collection.provenance_type,
        home_id=document_db_collection.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _document_db_collection_from_nested(
    nested: DocumentDBCollectionNested,
) -> DocumentDBCollection:
    """Convert nested format to flat DocumentDBCollection."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else DocumentDBCollectionAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DOCUMENT_DB_COLLECTION_REL_FIELDS,
        DocumentDBCollectionRelationshipAttributes,
    )
    return DocumentDBCollection(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_document_db_collection_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _document_db_collection_to_nested_bytes(
    document_db_collection: DocumentDBCollection, serde: Serde
) -> bytes:
    """Convert flat DocumentDBCollection to nested JSON bytes."""
    return serde.encode(_document_db_collection_to_nested(document_db_collection))


def _document_db_collection_from_nested_bytes(
    data: bytes, serde: Serde
) -> DocumentDBCollection:
    """Convert nested JSON bytes to flat DocumentDBCollection."""
    nested = serde.decode(data, DocumentDBCollectionNested)
    return _document_db_collection_from_nested(nested)


